class CreditCardInfo {
  final String cardNumber;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String cardHolderName;

  CreditCardInfo({
    required this.cardNumber,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    required this.cardHolderName,
  });

  bool validate() {
    if (!_validateCardNumber(cardNumber)) return false;
    if (!_validateExpiryDate(expiryMonth, expiryYear)) return false;
    if (!_validateCVV(cvv)) return false;
    if (cardHolderName.trim().isEmpty) return false;
    return true;
  }

  bool _validateCardNumber(String number) {
    final cleanNumber = number.replaceAll(RegExp(r'\s+'), '');
    if (cleanNumber.length < 13 || cleanNumber.length > 19) return false;
    
    int sum = 0;
    bool alternate = false;
    for (int i = cleanNumber.length - 1; i >= 0; i--) {
      int digit = int.parse(cleanNumber[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool _validateExpiryDate(String month, String year) {
    try {
      final m = int.parse(month);
      final y = int.parse(year);
      if (m < 1 || m > 12) return false;
      
      final now = DateTime.now();
      final expiry = DateTime(y + 2000, m);
      return expiry.isAfter(now);
    } catch (e) {
      return false;
    }
  }

  bool _validateCVV(String cvv) {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }

  String getMaskedCardNumber() {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }
}

