class StripePaymentGateway implements PaymentGateway {
  final PaymentConfig config;
  final String baseUrl;

  StripePaymentGateway(this.config)
      : baseUrl = config.environment == PaymentEnvironment.production
            ? 'https://api.stripe.com/v1'
            : 'https://api.stripe.com/v1';

  @override
  Future<PaymentResult> processPayment(
    double amount,
    String currency,
    Map<String, dynamic> paymentDetails,
  ) async {
    try {
      final amountInCents = (amount * 100).toInt();

      final response = await http.post(
        Uri.parse('$baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer ${config.secretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': amountInCents.toString(),
          'currency': currency.toLowerCase(),
          'payment_method': paymentDetails['payment_method_id'],
          'confirm': 'true',
          'metadata[order_id]': paymentDetails['order_id'],
        },
      );

      final responseData = jsonDecode(response.body);

      if (response.statusCode == 200) {
        final transaction = PaymentTransaction(
          transactionId: responseData['id'],
          orderId: paymentDetails['order_id'],
          amount: amount,
          currency: currency,
          method: PaymentMethod.stripe,
          status: _mapStripeStatus(responseData['status']),
          timestamp: DateTime.now(),
          metadata: responseData,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
          additionalData: responseData,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: responseData['error']?['message'] ?? 'Payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Payment processing error: $e',
      );
    }
  }

  @override
  Future<PaymentResult> refundTransaction(
      String transactionId, double? amount) async {
    try {
      final body = <String, String>{
        'payment_intent': transactionId,
      };

      if (amount != null) {
        body['amount'] = (amount * 100).toInt().toString();
      }

      final response = await http.post(
        Uri.parse('$baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer ${config.secretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body,
      );

      final responseData = jsonDecode(response.body);

      if (response.statusCode == 200) {
        final transaction = PaymentTransaction(
          transactionId: responseData['id'],
          orderId: transactionId,
          amount: amount ?? 0,
          currency: responseData['currency'].toUpperCase(),
          method: PaymentMethod.stripe,
          status: TransactionStatus.refunded,
          timestamp: DateTime.now(),
          metadata: responseData,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: responseData['error']?['message'] ?? 'Refund failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund processing error: $e',
      );
    }
  }

  @override
  Future<bool> validatePayment(String transactionId) async {
    try {
      final response = await http.get(
        Uri.parse('$baseUrl/payment_intents/$transactionId'),
        headers: {
          'Authorization': 'Bearer ${config.secretKey}',
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['status'] == 'succeeded';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  TransactionStatus _mapStripeStatus(String status) {
    switch (status) {
      case 'succeeded':
        return TransactionStatus.completed;
      case 'processing':
        return TransactionStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
        return TransactionStatus.pending;
      case 'canceled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }
}

class PayPalPaymentGateway implements PaymentGateway {
  final PaymentConfig config;
  final String baseUrl;

  PayPalPaymentGateway(this.config)
      : baseUrl = config.environment == PaymentEnvironment.production
            ? 'https://api-m.paypal.com'
            : 'https://api-m.sandbox.paypal.com';

  Future<String?> _getAccessToken() async {
    try {
      final credentials = base64Encode(
          utf8.encode('${config.apiKey}:${config.secretKey}'));

      final response = await http.post(
        Uri.parse('$baseUrl/v1/oauth2/token'),
        headers: {
          'Authorization': 'Basic $credentials',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {'grant_type': 'client_credentials'},
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['access_token'];
      }
      return null;
    } catch (e) {
      return null;
    }
  }

  @override
  Future<PaymentResult> processPayment(
    double amount,
    String currency,
    Map<String, dynamic> paymentDetails,
  ) async {
    try {
      final accessToken = await _getAccessToken();
      if (accessToken == null) {
        return PaymentResult(
          success: false,
          errorMessage: 'Failed to authenticate with PayPal',
        );
      }

      final orderData = {
        'intent': 'CAPTURE',
        'purchase_units': [
          {
            'reference_id': paymentDetails['order_id'],
            'amount': {
              'currency_code': currency,
              'value': amount.toStringAsFixed(2),
            },
          }
        ],
        'payment_source': paymentDetails['payment_source'],
      };

      final response = await http.post(
        Uri.parse('$baseUrl/v2/checkout/orders'),
        headers: {
          'Authorization': 'Bearer $accessToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode(orderData),
      );

      final responseData = jsonDecode(response.body);

      if (response.statusCode == 201) {
        final transaction = PaymentTransaction(
          transactionId: responseData['id'],
          orderId: paymentDetails['order_id'],
          amount: amount,
          currency: currency,
          method: PaymentMethod.paypal,
          status: _mapPayPalStatus(responseData['status']),
          timestamp: DateTime.now(),
          metadata: responseData,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
          additionalData: responseData,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: responseData['message'] ?? 'Payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Payment processing error: $e',
      );
    }
  }

  @override
  Future<PaymentResult> refundTransaction(
      String transactionId, double? amount) async {
    try {
      final accessToken = await _getAccessToken();
      if (accessToken == null) {
        return PaymentResult(
          success: false,
          errorMessage: 'Failed to authenticate with PayPal',
        );
      }

      final refundData = amount != null
          ? {
              'amount': {
                'currency_code': config.currency,
                'value': amount.toStringAsFixed(2),
              }
            }
          : {};

      final response = await http.post(
        Uri.parse('$baseUrl/v2/payments/captures/$transactionId/refund'),
        headers: {
          'Authorization': 'Bearer $accessToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode(refundData),
      );

      final responseData = jsonDecode(response.body);

      if (response.statusCode == 201) {
        final transaction = PaymentTransaction(
          transactionId: responseData['id'],
          orderId: transactionId,
          amount: amount ?? 0,
          currency: config.currency,
          method: PaymentMethod.paypal,
          status: TransactionStatus.refunded,
          timestamp: DateTime.now(),
          metadata: responseData,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: responseData['message'] ?? 'Refund failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund processing error: $e',
      );
    }
  }

  @override
  Future<bool> validatePayment(String transactionId) async {
    try {
      final accessToken = await _getAccessToken();
      if (accessToken == null) return false;

      final response = await http.get(
        Uri.parse('$baseUrl/v2/checkout/orders/$transactionId'),
        headers: {
          'Authorization': 'Bearer $accessToken',
        },
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['status'] == 'COMPLETED';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  TransactionStatus _mapPayPalStatus(String status) {
    switch (status) {
      case 'COMPLETED':
        return TransactionStatus.completed;
      case 'APPROVED':
        return TransactionStatus.processing;
      case 'CREATED':
        return TransactionStatus.pending;
      case 'VOIDED':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }
}

class InAppPurchaseManager {
  static const MethodChannel _channel =
      MethodChannel('com.payment.iap/channel');

  final StreamController<PaymentTransaction> _purchaseController =
      StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get purchaseStream => _purchaseController.stream;

  Future<void> initialize() async {
    try {
      _channel.setMethodCallHandler(_handleMethodCall);
      await _channel.invokeMethod('initialize');
    } catch (e) {
      throw PaymentException('Failed to initialize IAP: $e');
    }
  }

  Future<List<PaymentProduct>> getProducts(List<String> productIds) async {
    try {
      final result = await _channel.invokeMethod('getProducts', {
        'productIds': productIds,
      });

      final List<dynamic> products = result;
      return products
          .map((p) => PaymentProduct.fromJson(Map<String, dynamic>.from(p)))
          .toList();
    } catch (e) {
      throw PaymentException('Failed to get products: $e');
    }
  }

  Future<PaymentResult> purchaseProduct(String productId) async {
    try {
      final result = await _channel.invokeMethod('purchaseProduct', {
        'productId': productId,
      });

      if (result['success']) {
        final transaction = PaymentTransaction(
          transactionId: result['transactionId'],
          orderId: result['orderId'] ?? productId,
          amount: result['amount'],
          currency: result['currency'] ?? 'USD',
          method: PaymentMethod.inAppPurchase,
          status: TransactionStatus.completed,
          timestamp: DateTime.now(),
          receiptData: result['receiptData'],
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: result['error'] ?? 'Purchase failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Purchase error: $e',
      );
    }
  }

  Future<bool> verifyPurchase(String receiptData) async {
    try {
      final result = await _channel.invokeMethod('verifyPurchase', {
        'receiptData': receiptData,
      });
      return result ?? false;
    } catch (e) {
      return false;
    }
  }

  Future<void> completePurchase(String transactionId) async {
    try {
      await _channel.invokeMethod('completePurchase', {
        'transactionId': transactionId,
      });
    } catch (e) {
      throw PaymentException('Failed to complete purchase: $e');
    }
  }

  Future<List<PaymentTransaction>> restorePurchases() async {
    try {
      final result = await _channel.invokeMethod('restorePurchases');
      final List<dynamic> transactions = result;
      
      return transactions
          .map((t) =>
              PaymentTransaction.fromJson(Map<String, dynamic>.from(t)))
          .toList();
    } catch (e) {
      throw PaymentException('Failed to restore purchases: $e');
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    switch (call.method) {
      case 'onPurchaseUpdate':
        final transaction = PaymentTransaction.fromJson(
            Map<String, dynamic>.from(call.arguments));
        _purchaseController.add(transaction);
        break;
    }
  }

  void dispose() {
    _purchaseController.close();
  }
}

class MobileWalletManager {
  static const MethodChannel _channel =
      MethodChannel('com.payment.wallet/channel');

  Future<bool> isApplePayAvailable() async {
    if (!Platform.isIOS) return false;
    try {
      return await _channel.invokeMethod('isApplePayAvailable') ?? false;
    } catch (e) {
      return false;
    }
  }

  Future<bool> isGooglePayAvailable() async {
    if (!Platform.isAndroid) return false;
    try {
      return await _channel.invokeMethod('isGooglePayAvailable') ?? false;
    } catch (e) {
      return false;
    }
  }

  Future<PaymentResult> processApplePayPayment({
    required double amount,
    required String currency,
    required String merchantId,
    required String countryCode,
    String? orderId,
  }) async {
    if (!Platform.isIOS) {
      return PaymentResult(
        success: false,
        errorMessage: 'Apple Pay is only available on iOS',
      );
    }

    try {
      final result = await _channel.invokeMethod('processApplePay', {
        'amount': amount,
        'currency': currency,
        'merchantId': merchantId,
        'countryCode': countryCode,
        'orderId': orderId,
      });

      if (result['success']) {
        final transaction = PaymentTransaction(
          transactionId: result['transactionId'],
          orderId: orderId ?? result['transactionId'],
          amount: amount,
          currency: currency,
          method: PaymentMethod.applePay,
          status: TransactionStatus.completed,
          timestamp: DateTime.now(),
          metadata: result,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
          additionalData: result,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: result['error'] ?? 'Apple Pay payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Apple Pay error: $e',
      );
    }
  }

  Future<PaymentResult> processGooglePayPayment({
    required double amount,
    required String currency,
    required String merchantId,
    required String gatewayToken,
    String? orderId,
  }) async {
    if (!Platform.isAndroid) {
      return PaymentResult(
        success: false,
        errorMessage: 'Google Pay is only available on Android',
      );
    }

    try {
      final result = await _channel.invokeMethod('processGooglePay', {
        'amount': amount,
        'currency': currency,
        'merchantId': merchantId,
        'gatewayToken': gatewayToken,
        'orderId': orderId,
      });

      if (result['success']) {
        final transaction = PaymentTransaction(
          transactionId: result['transactionId'],
          orderId: orderId ?? result['transactionId'],
          amount: amount,
          currency: currency,
          method: PaymentMethod.googlePay,
          status: TransactionStatus.completed,
          timestamp: DateTime.now(),
          metadata: result,
        );

        return PaymentResult(
          success: true,
          transaction: transaction,
          additionalData: result,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: result['error'] ?? 'Google Pay payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Google Pay error: $e',
      );
    }
  }
