class PaymentSecurityManager {
  String encryptSensitiveData(String data, String key) {
    final keyBytes = utf8.encode(key.padRight(32).substring(0, 32));
    final dataBytes = utf8.encode(data);
    
    final encrypted = <int>[];
    for (int i = 0; i < dataBytes.length; i++) {
      encrypted.add(dataBytes[i] ^ keyBytes[i % keyBytes.length]);
    }
    
    return base64Encode(encrypted);
  }

  String decryptSensitiveData(String encryptedData, String key) {
    final keyBytes = utf8.encode(key.padRight(32).substring(0, 32));
    final encryptedBytes = base64Decode(encryptedData);
    
    final decrypted = <int>[];
    for (int i = 0; i < encryptedBytes.length; i++) {
      decrypted.add(encryptedBytes[i] ^ keyBytes[i % keyBytes.length]);
    }
    
    return utf8.decode(decrypted);
  }

  String generateTransactionHash(PaymentTransaction transaction) {
    final data = '${transaction.transactionId}'
        '${transaction.orderId}'
        '${transaction.amount}'
        '${transaction.currency}'
        '${transaction.timestamp.millisecondsSinceEpoch}';
    
    return sha256.convert(utf8.encode(data)).toString();
  }

  bool validateTransactionHash(
      PaymentTransaction transaction, String expectedHash) {
    final computedHash = generateTransactionHash(transaction);
    return computedHash == expectedHash;
  }

  String generatePaymentToken(Map<String, dynamic> paymentData, String secret) {
    final payload = jsonEncode(paymentData);
    final signature = hmacSha256(payload, secret);
    final token = base64Encode(utf8.encode('$payload.$signature'));
    return token;
  }

  bool validatePaymentToken(String token, String secret) {
    try {
      final decoded = utf8.decode(base64Decode(token));
      final parts = decoded.split('.');
      if (parts.length != 2) return false;

      final payload = parts[0];
      final providedSignature = parts[1];
      final expectedSignature = hmacSha256(payload, secret);

      return providedSignature == expectedSignature;
    } catch (e) {
      return false;
    }
  }

  String hmacSha256(String data, String secret) {
    final key = utf8.encode(secret);
    final bytes = utf8.encode(data);
    final hmac = Hmac(sha256, key);
    return hmac.convert(bytes).toString();
  }
}

class TransactionLogger {
  final SharedPreferences _prefs;
  static const String _logKey = 'payment_transaction_logs';

  TransactionLogger(this._prefs);

  Future<void> logTransaction(PaymentTransaction transaction) async {
    try {
      final logs = await getTransactionLogs();
      logs.add(transaction);

      final logsJson = logs.map((t) => t.toJson()).toList();
      await _prefs.setString(_logKey, jsonEncode(logsJson));
    } catch (e) {
      debugPrint('Failed to log transaction: $e');
    }
  }

  Future<List<PaymentTransaction>> getTransactionLogs() async {
    try {
      final logsString = _prefs.getString(_logKey);
      if (logsString == null) return [];

      final List<dynamic> logsJson = jsonDecode(logsString);
      return logsJson
          .map((json) =>
              PaymentTransaction.fromJson(Map<String, dynamic>.from(json)))
          .toList();
    } catch (e) {
      debugPrint('Failed to get transaction logs: $e');
      return [];
    }
  }

  Future<void> clearLogs() async {
    await _prefs.remove(_logKey);
  }

  Future<List<PaymentTransaction>> getTransactionsByStatus(
      TransactionStatus status) async {
    final logs = await getTransactionLogs();
    return logs.where((t) => t.status == status).toList();
  }

  Future<List<PaymentTransaction>> getTransactionsByDateRange(
      DateTime start, DateTime end) async {
    final logs = await getTransactionLogs();
    return logs
        .where((t) =>
            t.timestamp.isAfter(start) && t.timestamp.isBefore(end))
        .toList();
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final Map<PaymentMethod, PaymentGateway> _gateways = {};
  final InAppPurchaseManager _iapManager;
  final MobileWalletManager _walletManager;
  final PaymentSecurityManager _securityManager;
  final TransactionLogger _logger;

  final StreamController<PaymentTransaction> _transactionController =
      StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionStream =>
      _transactionController.stream;

  PaymentProcessor({
    required this.config,
    required SharedPreferences prefs,
  })  : _iapManager = InAppPurchaseManager(),
        _walletManager = MobileWalletManager(),
        _securityManager = PaymentSecurityManager(),
        _logger = TransactionLogger(prefs) {
    _initializeGateways();
  }

  void _initializeGateways() {
    _gateways[PaymentMethod.stripe] = StripePaymentGateway(config);
    _gateways[PaymentMethod.paypal] = PayPalPaymentGateway(config);
  }

  Future<void> initialize() async {
    await _iapManager.initialize();
    
    _iapManager.purchaseStream.listen((transaction) {
      _transactionController.add(transaction);
      _logger.logTransaction(transaction);
    });
  }

  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    required Map<String, dynamic> paymentDetails,
  }) async {
    try {
      PaymentResult result;

      switch (method) {
        case PaymentMethod.applePay:
          result = await _walletManager.processApplePayPayment(
            amount: amount,
            currency: currency,
            merchantId: config.merchantId,
            countryCode: config.countryCode,
            orderId: paymentDetails['order_id'],
          );
          break;

        case PaymentMethod.googlePay:
          result = await _walletManager.processGooglePayPayment(
            amount: amount,
            currency: currency,
            merchantId: config.merchantId,
            gatewayToken: paymentDetails['gateway_token'],
            orderId: paymentDetails['order_id'],
          );
          break;

        case PaymentMethod.inAppPurchase:
          result = await _iapManager.purchaseProduct(
            paymentDetails['product_id'],
          );
          break;

        case PaymentMethod.stripe:
        case PaymentMethod.paypal:
        case PaymentMethod.creditCard:
        case PaymentMethod.debitCard:
          final gateway = _gateways[method];
          if (gateway == null) {
            result = PaymentResult(
              success: false,
              errorMessage: 'Payment gateway not configured for $method',
            );
          } else {
            result = await gateway.processPayment(
              amount,
              currency,
              paymentDetails,
            );
          }
          break;
      }

      if (result.transaction != null) {
        _transactionController.add(result.transaction!);
        await _logger.logTransaction(result.transaction!);
      }

      return result;
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Payment processing failed: $e',
      );
    }
  }

  Future<PaymentResult> refundPayment({
    required String transactionId,
    required PaymentMethod method,
    double? amount,
  }) async {
    try {
      final gateway = _gateways[method];
      if (gateway == null) {
        return PaymentResult(
          success: false,
          errorMessage: 'Refund not supported for $method',
        );
      }

      final result = await gateway.refundTransaction(transactionId, amount);

      if (result.transaction != null) {
        _transactionController.add(result.transaction!);
        await _logger.logTransaction(result.transaction!);
      }

      return result;
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund failed: $e',
      );
    }
  }

  Future<bool> validateTransaction(
      String transactionId, PaymentMethod method) async {
    try {
      final gateway = _gateways[method];
      if (gateway == null) return false;

      return await gateway.validatePayment(transactionId);
    } catch (e) {
      return false;
    }
  }

  Future<List<PaymentProduct>> getAvailableProducts(
      List<String> productIds) async {
    return await _iapManager.getProducts(productIds);
  }

  Future<List<PaymentTransaction>> restorePurchases() async {
    return await _iapManager.restorePurchases();
  }

  Future<bool> isApplePayAvailable() async {
    return await _walletManager.isApplePayAvailable();
  }

  Future<bool> isGooglePayAvailable() async {
    return await _walletManager.isGooglePayAvailable();
  }

  Future<List<PaymentTransaction>> getTransactionHistory() async {
    return await _logger.getTransactionLogs();
  }

  Future<List<PaymentTransaction>> getTransactionsByStatus(
      TransactionStatus status) async {
    return await _logger.getTransactionsByStatus(status);
  }

  String encryptCardData(CreditCardInfo cardInfo, String encryptionKey) {
    final cardData = jsonEncode({
      'number': cardInfo.cardNumber,
      'expiry': '${cardInfo.expiryMonth}/${cardInfo.expiryYear}',
      'cvv': cardInfo.cvv,
      'holder': cardInfo.cardHolderName,
    });
    return _securityManager.encryptSensitiveData(cardData, encryptionKey);
  }

  String generatePaymentToken(Map<String, dynamic> paymentData) {
    return _securityManager.generatePaymentToken(paymentData, config.secretKey);
  }

  bool validatePaymentToken(String token) {
    return _securityManager.validatePaymentToken(token, config.secretKey);
  }

  void dispose() {
    _transactionController.close();
    _iapManager.dispose();
  }
}

class PaymentWidget extends StatefulWidget {
  final PaymentProcessor processor;
  final double amount;
  final String currency;
  final Function(PaymentResult) onPaymentComplete;

  const PaymentWidget({
    Key? key,
    required this.processor,
    required this.amount,
    required this.currency,
    required this.onPaymentComplete,
  }) : super(key: key);

  @override
  State<PaymentWidget> createState() => _PaymentWidgetState();
}

class _PaymentWidgetState extends State<PaymentWidget> {
  PaymentMethod? _selectedMethod;
  bool _isProcessing = false;

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text(
          'Payment Amount: ${widget.currency} ${widget.amount.toStringAsFixed(2)}',
          style: const TextStyle(fontSize: 24, fontWeight: FontWeight.bold),
        ),
        const SizedBox(height: 20),
        _buildPaymentMethodSelector(),
        const SizedBox(height: 20),
        if (_isProcessing)
          const CircularProgressIndicator()
        else
          ElevatedButton(
            onPressed: _selectedMethod != null ? _processPayment : null,
            child: const Text('Pay Now'),
          ),
      ],
    );
  }

  Widget _buildPaymentMethodSelector() {
    return Column(
      children: [
        ListTile(
          title: const Text('Credit Card'),
          leading: Radio<PaymentMethod>(
            value: PaymentMethod.creditCard,
            groupValue: _selectedMethod,
            onChanged: (value) => setState(() => _selectedMethod = value),
          ),
        ),
        ListTile(
          title: const Text('Apple Pay'),
          leading: Radio<PaymentMethod>(
            value: PaymentMethod.applePay,
            groupValue: _selectedMethod,
            onChanged: (value) => setState(() => _selectedMethod = value),
          ),
        ),
        ListTile(
          title: const Text('Google Pay'),
          leading: Radio<PaymentMethod>(
            value: PaymentMethod.googlePay,
            groupValue: _selectedMethod,
            onChanged: (value) => setState(() => _selectedMethod = value),
          ),
        ),
      ],
    );
  }

  Future<void> _processPayment() async {
    setState(() => _isProcessing = true);

    final result = await widget.processor.processPayment(
      amount: widget.amount,
      currency: widget.currency,
      method: _selectedMethod!,
      paymentDetails: {
        'order_id': DateTime.now().millisecondsSinceEpoch.toString(),
      },
    );

    setState(() => _isProcessing = false);
    widget.onPaymentComplete(result);
  }
}